#include "Nexiora/Reasoning/NxConversationalContext.h"
#include <stdio.h>
#include <string.h>
static int check(int c,const char*m){if(!c){fprintf(stderr,"NxConversationalContextTests: FAIL: %s\n",m);return 0;}return 1;}
int main(void){const char* ev="nx_cc_test.nxevidence";const char* ss="nx_cc_test.nxconversation";FILE*f=fopen(ev,"wb");NxCcTurnResult r;if(!f)return 1;fputs("nxevidence/1\nchunk=1\nsource=demo@1\ntext=La memoria episodica conserva experiencias personales con tiempo y contexto.\nchunk=2\nsource=demo@2\ntext=La memoria semantica conserva conocimientos generales sin contexto autobiografico.\n",f);fclose(f);if(!check(NxConversationalContext_Create(ss,ev,"memoria episodica")==NX_CC_OK,"create failed"))return 1;if(!check(NxConversationalContext_Ask(ss,"Que conserva la memoria episodica",&r)==NX_CC_OK,"first ask failed"))return 1;if(!check(r.grounded.evidence_count>0,"first answer lacks evidence"))return 1;if(!check(NxConversationalContext_Ask(ss,"Y como se diferencia de la semantica",&r)==NX_CC_OK,"follow-up failed"))return 1;if(!check(strstr(r.resolved_question,"memoria episodica")!=NULL,"reference was not resolved"))return 1;if(!check(r.turn_index==2U,"turn index was not persisted"))return 1;remove(ev);remove(ss);puts("NxConversationalContextTests: PASS");return 0;}
